//! # Saturation Integration Test
//!
//! Comprehensive test of saturation metadata in .rknot format.
//! Covers:
//! 1. Creating saturation maps from profiling data
//! 2. Embedding maps in RknotHeader
//! 3. Loading and querying saturation data
//! 4. Using sparse contexts in inference

use distributed_inference::inference_saturation::{SaturationHandle, SparseFfnContext};
use distributed_inference::rknot::encoder_config::KnotEncoderConfig;
use distributed_inference::rknot::format::{ArchMeta, Rknot, RknotHeader, RknotLayerRef};
use distributed_inference::rknot::saturation_metadata::{
    LayerFrozenBitmask, LayerSaturationStat, SaturationMaps,
};

#[test]
fn test_layer_frozen_bitmask_creation_and_access() {
    // Create a bitmask for a layer with 8192 neurons
    let mut mask = LayerFrozenBitmask::new(0, 8192);

    // Initially, no neurons are frozen
    assert_eq!(mask.num_frozen(), 0);
    assert_eq!(mask.pct_frozen(), 0.0);

    // Freeze some neurons
    for i in 0..800 {
        mask.freeze_neuron(i);
    }

    // Verify frozen count
    assert_eq!(mask.num_frozen(), 800);
    assert!((mask.pct_frozen() - (800.0 / 8192.0 * 100.0)).abs() < 0.01);

    // Verify frozen status
    assert!(mask.is_frozen(0));
    assert!(mask.is_frozen(799));
    assert!(!mask.is_frozen(800));
    assert!(!mask.is_frozen(8191));

    // Verify speedup estimation (800 frozen = ~9.77%, speedup ~1.11x)
    let speedup = mask.estimated_speedup();
    assert!(speedup >= 1.09 && speedup <= 1.13);
}

#[test]
fn test_saturation_maps_embedding_in_header() {
    // Create saturation maps for a 32-layer model
    let mut maps = SaturationMaps::new(32, "variance+gradient".to_string())
        .with_model_name("phi3-mini-4k-instruct".to_string());

    // Add bitmasks for layers 0, 15, 31 (sparse sampling)
    for layer_id in [0, 15, 31] {
        let mut mask = LayerFrozenBitmask::new(layer_id, 8192);
        // Freeze 10% of neurons per layer
        for i in 0..(8192 / 10) {
            mask.freeze_neuron(i);
        }
        maps = maps.insert_layer_mask(mask);
    }

    // Add statistics
    for layer_id in 0..3 {
        let stat = LayerSaturationStat {
            layer_id: layer_id as u32,
            pct_frozen_ffn: 10.0,
            estimated_speedup: 1.11,
            profile_timestamp: None,
            profile_probe: Some("phi3-calib-corpus".to_string()),
        };
        maps = maps.add_stat(stat);
    }

    // Verify maps
    assert_eq!(maps.ffn_frozen_per_layer.len(), 3);
    assert_eq!(maps.stats.len(), 3);
    assert!(maps.model_name.is_some());

    // Create an RknotHeader with the maps
    let header = RknotHeader {
        arch_meta: ArchMeta {
            arch: "phi3".to_string(),
            hidden_dim: 3072,
            num_layers: 32,
            num_heads: 32,
            num_kv_heads: 32,
            head_dim: 96,
            intermediate_size: 8192,
            vocab_size: 32064,
            rms_norm_eps: 1e-5,
            rope_theta: 10000.0,
        },
        layers: vec![],
        encoder_version: "rknot-encoder/0.2.0".to_string(),
        calibration_probe: None,
        saturation_maps: Some(maps.clone()),
    };

    // Verify header has saturation data
    assert!(header.saturation_maps.is_some());
    if let Some(maps) = &header.saturation_maps {
        assert_eq!(maps.ffn_frozen_per_layer.len(), 3);
        assert!(maps.is_ffn_neuron_frozen(0, 100));
        assert!(!maps.is_ffn_neuron_frozen(0, 900));
    }
}

#[test]
fn test_saturation_handle_query_interface() {
    // Create saturation maps
    let mut mask0 = LayerFrozenBitmask::new(0, 8192);
    let mut mask1 = LayerFrozenBitmask::new(1, 8192);

    // Layer 0: 10% frozen
    for i in 0..(8192 / 10) {
        mask0.freeze_neuron(i);
    }

    // Layer 1: 50% frozen
    for i in 0..(8192 / 2) {
        mask1.freeze_neuron(i);
    }

    let maps = SaturationMaps::new(32, "variance+gradient".to_string())
        .insert_layer_mask(mask0)
        .insert_layer_mask(mask1);

    // Create handle
    let handle = SaturationHandle::with_maps(maps);

    // Test queries
    assert!(handle.is_available());
    assert!(handle.is_ffn_neuron_frozen(0, 100));
    assert!(!handle.is_ffn_neuron_frozen(0, 900));
    assert!(handle.is_ffn_neuron_frozen(1, 4000));
    assert!(!handle.is_ffn_neuron_frozen(1, 5000));

    // Test speedup estimates
    let speedup_0 = handle.ffn_speedup_estimate(0);
    let speedup_1 = handle.ffn_speedup_estimate(1);
    assert!(speedup_0 > 1.0 && speedup_0 < 1.2);
    assert!(speedup_1 >= 1.9 && speedup_1 <= 2.1);

    // Test mean speedup
    let mean = handle.mean_speedup();
    assert!(mean > 1.0);
}

#[test]
fn test_sparse_ffn_context_creation() {
    // Test dense context (no saturation)
    let dense_ctx = SparseFfnContext::dense(0, 8192);
    assert!(!dense_ctx.can_apply_sparse());
    assert_eq!(dense_ctx.estimated_speedup(), 1.0);

    // Test context with saturation
    let mut frozen = vec![0u8; 1024]; // 8192 neurons → 1024 bytes
    for byte_idx in 0..100 {
        frozen[byte_idx] = 0xFF; // 800 neurons frozen (100 bytes × 8)
    }

    let sparse_ctx = SparseFfnContext::from_saturation(0, 8192, frozen, 800);
    assert!(sparse_ctx.can_apply_sparse());
    assert_eq!(sparse_ctx.num_frozen, 800);
    assert!(sparse_ctx.is_frozen(0));
    assert!(sparse_ctx.is_frozen(799));
    assert!(!sparse_ctx.is_frozen(800));

    // Verify speedup (800 frozen = ~9.77%, speedup ~1.11x)
    let speedup = sparse_ctx.estimated_speedup();
    assert!(speedup >= 1.09 && speedup <= 1.13);
}

#[test]
fn test_sparse_ffn_context_from_handle() {
    // Create maps with varying saturation levels
    let mut mask = LayerFrozenBitmask::new(0, 8192);
    for i in 0..2048 {
        mask.freeze_neuron(i);
    }

    let maps = SaturationMaps::new(32, "variance+gradient".to_string()).insert_layer_mask(mask);

    let handle = SaturationHandle::with_maps(maps);

    // Load context from handle
    let ctx = SparseFfnContext::from_handle(&handle, 0, 8192);
    assert!(ctx.can_apply_sparse());
    assert_eq!(ctx.num_frozen, 2048);
    assert!((ctx.pct_frozen() - 25.0).abs() < 0.01);

    // Verify sparse neuron lookup
    assert!(ctx.is_frozen(1000));
    assert!(!ctx.is_frozen(3000));
    // Speedup: 2048 frozen = 25%, gives ~1.33x speedup
    assert!(ctx.estimated_speedup() >= 1.31 && ctx.estimated_speedup() <= 1.35);
}

#[test]
fn test_encoder_config_with_saturation() {
    // Create saturation maps
    let mut mask = LayerFrozenBitmask::new(0, 8192);
    for i in 0..(8192 / 5) {
        mask.freeze_neuron(i);
    }
    let maps = SaturationMaps::new(32, "variance+gradient".to_string()).insert_layer_mask(mask);

    // Create encoder config with saturation
    let config =
        KnotEncoderConfig::new("rknot-encoder/0.2.0".to_string()).with_saturation(maps, true, true);

    assert!(config.has_saturation());
    assert!(config.apply_saturation_pruning);
    assert!(config.log_saturation_stats);
}

#[test]
fn test_saturation_maps_serialization() {
    // Create maps
    let mut mask = LayerFrozenBitmask::new(0, 8192);
    for i in 0..100 {
        mask.freeze_neuron(i);
    }

    let maps = SaturationMaps::new(32, "variance+gradient".to_string())
        .with_model_name("phi3-mini".to_string())
        .insert_layer_mask(mask);

    // Serialize to JSON
    let json = serde_json::to_string(&maps).expect("serialization failed");
    assert!(json.contains("phi3-mini"));
    assert!(json.contains("variance+gradient"));

    // Deserialize back
    let maps_restored: SaturationMaps =
        serde_json::from_str(&json).expect("deserialization failed");
    assert_eq!(maps_restored.model_name, Some("phi3-mini".to_string()));
    assert_eq!(maps_restored.ffn_frozen_per_layer.len(), 1);
    assert!(maps_restored.is_ffn_neuron_frozen(0, 50));
}

#[test]
fn test_multiple_layer_saturation_profiles() {
    // Create varied saturation profiles across layers
    let mut maps = SaturationMaps::new(4, "variance+gradient".to_string());

    // Layer 0: 5% frozen
    let mut mask0 = LayerFrozenBitmask::new(0, 8192);
    for i in 0..(8192 / 20) {
        mask0.freeze_neuron(i);
    }
    maps = maps.insert_layer_mask(mask0);

    // Layer 1: 25% frozen
    let mut mask1 = LayerFrozenBitmask::new(1, 8192);
    for i in 0..(8192 / 4) {
        mask1.freeze_neuron(i);
    }
    maps = maps.insert_layer_mask(mask1);

    // Layer 2: 50% frozen
    let mut mask2 = LayerFrozenBitmask::new(2, 8192);
    for i in 0..(8192 / 2) {
        mask2.freeze_neuron(i);
    }
    maps = maps.insert_layer_mask(mask2);

    // Layer 3: 80% frozen
    let mut mask3 = LayerFrozenBitmask::new(3, 8192);
    for i in 0..((8192 * 4) / 5) {
        mask3.freeze_neuron(i);
    }
    maps = maps.insert_layer_mask(mask3);

    // Verify profiles
    assert_eq!(maps.ffn_frozen_per_layer.len(), 4);

    // Layer 0: ~5%
    let s0 = maps.ffn_speedup_estimate(0);
    assert!(s0 >= 1.0 && s0 < 1.1);

    // Layer 1: ~25%
    let s1 = maps.ffn_speedup_estimate(1);
    assert!(s1 >= 1.3 && s1 < 1.4);

    // Layer 2: ~50%
    let s2 = maps.ffn_speedup_estimate(2);
    assert!(s2 >= 1.9 && s2 < 2.1);

    // Layer 3: ~80%
    let s3 = maps.ffn_speedup_estimate(3);
    assert!(s3 >= 4.5 && s3 < 5.5);

    // Mean speedup
    let mean = maps.mean_speedup();
    assert!(mean > 2.0); // Average of [1.05, 1.33, 2.0, 5.0] ≈ 2.3
}
